try {
  // Code that might throw
  const result = JSON.parse(userInput);
  console.log(result);
} catch (err) {
  // Runs only if something was thrown in try
  console.error('Parse failed:', err.message);
} finally {
  // Runs always — whether try succeeded or catch ran
  console.log('Done');
}

try {
  null.property; // TypeError
} catch (err) {
  console.log(err.name);    // 'TypeError'
  console.log(err.message); // "Cannot read properties of null..."
  console.log(err.stack);   // full stack trace string

  // ES2022: err.cause — the original error that caused this one
  const wrapped = new Error('High-level message', { cause: err });
  console.log(wrapped.cause === err); // true
}

// Bad: throws a string — no stack trace
function bad(n) {
  if (n < 0) throw 'Negative number'; // avoid
}

// Good: throw an Error instance
function validateAge(age) {
  if (typeof age !== 'number') {
    throw new TypeError(`Expected a number, got ${typeof age}`);
  }
  if (age < 0 || age > 150) {
    throw new RangeError(`Age ${age} is outside valid range 0–150`);
  }
  return age;
}

try {
  validateAge(-5);
} catch (err) {
  console.log(err instanceof RangeError); // true
  console.log(err.message); // 'Age -5 is outside valid range 0–150'
}

class AppError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'AppError'; // override default 'Error'
    this.code = code;
  }
}

class NetworkError extends AppError {
  constructor(message, statusCode) {
    super(message, 'NETWORK_ERROR');
    this.name = 'NetworkError';
    this.statusCode = statusCode;
  }
}

class ValidationError extends AppError {
  constructor(message, field) {
    super(message, 'VALIDATION_ERROR');
    this.name = 'ValidationError';
    this.field = field;
  }
}

// Usage
try {
  throw new NetworkError('Gateway timeout', 504);
} catch (err) {
  if (err instanceof NetworkError) {
    console.log(`Network error ${err.statusCode}: ${err.message}`);
  } else if (err instanceof ValidationError) {
    console.log(`Field '${err.field}' is invalid: ${err.message}`);
  } else {
    throw err; // re-throw unknown errors
  }
}

function loadConfig(json) {
  try {
    return JSON.parse(json);
  } catch (err) {
    if (err instanceof SyntaxError) {
      // We can handle malformed JSON specifically
      throw new Error('Config file contains invalid JSON', { cause: err });
    }
    // Unknown error — re-throw so it surfaces to the caller
    throw err;
  }
}

async function fetchWithTimeout(url) {
  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), 5000);

  try {
    const res = await fetch(url, { signal: controller.signal });
    return await res.json();
  } catch (err) {
    if (err.name === 'AbortError') {
      throw new Error('Request timed out after 5s');
    }
    throw err;
  } finally {
    clearTimeout(timer); // always clear the timer, success or failure
  }
}

import { useState } from 'react';

function JsonEditor() {
  const [input, setInput] = useState('');
  const [result, setResult] = useState(null);
  const [error, setError] = useState(null);

  function handleParse() {
    try {
      const parsed = JSON.parse(input);
      setResult(parsed);
      setError(null);
    } catch (err) {
      setError(err.message);
      setResult(null);
    }
  }

  return (
    <div>
      <textarea value={input} onChange={(e) => setInput(e.target.value)} />
      <button onClick={handleParse}>Parse</button>
      {error && <p style={{ color: 'red' }}>Invalid JSON: {error}</p>}
      {result && <pre>{JSON.stringify(result, null, 2)}</pre>}
    </div>
  );
}

function safeGetItem(key, defaultValue = null) {
  try {
    const raw = localStorage.getItem(key);
    return raw === null ? defaultValue : JSON.parse(raw);
  } catch {
    return defaultValue;
  }
}

function safeSetItem(key, value) {
  try {
    localStorage.setItem(key, JSON.stringify(value));
    return true;
  } catch (err) {
    console.warn('localStorage write failed:', err);
    return false;
  }
}

// ES2019: optional catch binding — no (err) needed
function parseOrNull(json) {
  try {
    return JSON.parse(json);
  } catch {
    return null;
  }
}

// BAD: swallows every error including programming bugs
try {
  processData(data);
} catch (err) {
  console.log('Something went wrong'); // TypeError? null ref? all hidden
}

// BETTER: only handle expected failures
try {
  processData(data);
} catch (err) {
  if (err instanceof ValidationError) {
    showFieldError(err.field, err.message);
  } else {
    throw err; // let unexpected errors surface
  }
}

// BUG: try/catch exits before the Promise rejects
try {
  fetch('/api/data'); // no await — try/catch misses the rejection
} catch (err) {
  // Never runs
}

// CORRECT: await inside try/catch in an async function
async function load() {
  try {
    const data = await fetch('/api/data');
    return data.json();
  } catch (err) {
    console.error('Fetch failed:', err);
  }
}

function processFile(content) {
  let parsed;
  try {
    parsed = JSON.parse(content);
  } catch (err) {
    throw new Error('Invalid JSON in file', { cause: err });
  }

  let validated;
  try {
    validated = validateSchema(parsed);
  } catch (err) {
    // Schema failure is separate from parse failure
    throw new ValidationError(err.message, err.field);
  }

  return validated;
}

// Using react-error-boundary (npm install react-error-boundary)
import { ErrorBoundary } from 'react-error-boundary';

function ErrorFallback({ error, resetErrorBoundary }) {
  return (
    <div>
      <h2>Something went wrong</h2>
      <p>{error.message}</p>
      <button onClick={resetErrorBoundary}>Try again</button>
    </div>
  );
}

export default function App() {
  return (
    <ErrorBoundary FallbackComponent={ErrorFallback}>
      <Dashboard />
    </ErrorBoundary>
  );
}

async function fetchUser(id) {
  try {
    const res = await fetch(`/api/users/${id}`);
    if (!res.ok) throw new Error(`HTTP ${res.status}`);
    return await res.json();
  } catch (err) {
    throw new Error(`Failed to load user ${id}`, { cause: err });
  }
}

async function loadDashboard(userId) {
  try {
    const user = await fetchUser(userId);
    console.log('Dashboard for', user.name);
  } catch (err) {
    console.error(err.message);       // Failed to load user 42
    console.error(err.cause.message); // HTTP 404
  }
}

// utils/safeParse.js
export function safeParse(json, fallback = null) {
  try {
    return JSON.parse(json);
  } catch {
    return fallback;
  }
}

// Typed wrapper with validation
export function safeParseWith(json, validate, fallback = null) {
  try {
    const value = JSON.parse(json);
    if (!validate(value)) throw new TypeError('Validation failed');
    return value;
  } catch {
    return fallback;
  }
}

// Usage in a React hook
function useStoredFilters() {
  const [filters, setFilters] = useState(() => {
    const raw = localStorage.getItem('filters');
    return safeParse(raw, { sort: 'asc', page: 1 });
  });
  return [filters, setFilters];
}

// utils/safeParse.test.js
import { describe, it, expect } from 'vitest';
import { safeParse, safeParseWith } from './safeParse';

describe('safeParse', () => {
  it('parses valid JSON', () => {
    expect(safeParse('{"a":1}')).toEqual({ a: 1 });
  });

  it('returns fallback on invalid JSON', () => {
    expect(safeParse('not-json', [])).toEqual([]);
  });

  it('returns null fallback by default', () => {
    expect(safeParse('{bad}')).toBeNull();
  });
});

// Testing a function that throws
function divide(a, b) {
  if (b === 0) throw new RangeError('Division by zero');
  return a / b;
}

describe('divide', () => {
  it('throws RangeError when dividing by zero', () => {
    expect(() => divide(4, 0)).toThrow(RangeError);
    expect(() => divide(4, 0)).toThrow('Division by zero');
  });

  it('returns the correct quotient', () => {
    expect(divide(10, 2)).toBe(5);
  });
});

// utils/reportError.js
export function reportError(err, context = {}) {
  // Replace with Sentry, Datadog, etc.
  console.error('[Error]', err.message, context);
  // Example: Sentry.captureException(err, { extra: context });
}

// In a component
async function submitForm(data) {
  try {
    await api.post('/submissions', data);
  } catch (err) {
    reportError(err, { form: 'checkout', userId: currentUser.id });
    setError('Submission failed. Please try again.');
  }
}

// Global unhandled rejection listener (main.jsx or index.js)
window.addEventListener('unhandledrejection', (event) => {
  reportError(event.reason, { type: 'unhandledRejection' });
});
